import{_ as i,o,c as t,ae as a}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"China Provider Expansion Round 2 Design","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-03-26-china-provider-expansion-round2-design.md","filePath":"superpowers/specs/2026-03-26-china-provider-expansion-round2-design.md"}'),r={name:"superpowers/specs/2026-03-26-china-provider-expansion-round2-design.md"};function n(s,e,d,l,c,p){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="china-provider-expansion-round-2-design" tabindex="-1">China Provider Expansion Round 2 Design <a class="header-anchor" href="#china-provider-expansion-round-2-design" aria-label="Permalink to &quot;China Provider Expansion Round 2 Design&quot;">​</a></h1><p><strong>Date:</strong> 2026-03-26</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>This design covers the next provider-expansion pass for Notemd after the initial China-focused provider rollout:</p><ol><li>Add <code>Qwen Code</code> as a dedicated coding-oriented preset instead of forcing users to overload the general <code>Qwen</code> preset.</li><li>Add <code>Z AI</code> as a separate preset for the international GLM/Zhipu entrypoint while keeping the existing <code>GLM</code> preset for the mainland China endpoint.</li><li>Add <code>Huawei Cloud MaaS</code> as a first-class preset for users who access hosted models through Huawei Cloud&#39;s OpenAI-compatible endpoint.</li><li>Update tests, documentation, and release materials so these providers ship with the same quality bar as existing presets.</li></ol><p>This round explicitly excludes providers that require new authentication schemes, provider-specific SDK logic, or a new transport type. The goal is to expand Chinese and China-adjacent provider support without increasing protocol complexity.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>The provider system should continue to use <code>src/llmProviders.ts</code> as the single source of truth for preset metadata. All three new providers should be implemented as registry entries and should reuse the existing <code>openai-compatible</code> transport path in <code>src/llmUtils.ts</code>.</p><p>No new transport should be introduced. Runtime calls should continue to flow through the shared OpenAI-compatible request builder and the centralized retry/fallback logic. Connection testing should continue to use provider metadata to decide whether a preset probes <code>/models</code> first or goes straight to <code>chat/completions</code>.</p><p>This means the implementation remains additive:</p><ul><li>new registry entries in <code>src/llmProviders.ts</code></li><li>new provider assertions in test files</li><li>documentation updates in <code>README.md</code>, <code>README_zh.md</code>, and <code>change.md</code></li><li>a patch release using the existing bilingual release-note workflow</li></ul><h2 id="provider-decisions" tabindex="-1">Provider Decisions <a class="header-anchor" href="#provider-decisions" aria-label="Permalink to &quot;Provider Decisions&quot;">​</a></h2><h3 id="_1-qwen-code" tabindex="-1">1. Qwen Code <a class="header-anchor" href="#_1-qwen-code" aria-label="Permalink to &quot;1. Qwen Code&quot;">​</a></h3><p><code>Qwen Code</code> should be added as its own preset rather than hidden as a suggested model under <code>Qwen</code>.</p><p>Rationale:</p><ul><li>latest Cline exposes it separately from general Qwen</li><li>users looking for coding-specialized models expect a direct preset</li><li>it fits the existing OpenAI-compatible transport and chat-first API testing model</li></ul><p>Expected shape:</p><ul><li>transport: <code>openai-compatible</code></li><li>category: <code>cloud</code></li><li>API key mode: <code>required</code></li><li>API test mode: <code>chat-only</code></li><li>base URL: DashScope compatible-mode endpoint</li><li>default model: a Qwen coding model such as <code>qwen3-coder-plus</code></li></ul><h3 id="_2-z-ai" tabindex="-1">2. Z AI <a class="header-anchor" href="#_2-z-ai" aria-label="Permalink to &quot;2. Z AI&quot;">​</a></h3><p><code>Z AI</code> should be added as a distinct preset even though Notemd already includes <code>GLM</code>.</p><p>Rationale:</p><ul><li>latest Cline treats <code>Z AI</code> as a first-class provider rather than a duplicate label</li><li>the current <code>GLM</code> preset is mainland-China oriented and points at <code>open.bigmodel.cn</code></li><li>a separate <code>Z AI</code> preset gives users an international endpoint without changing existing <code>GLM</code> behavior</li></ul><p>Expected shape:</p><ul><li>transport: <code>openai-compatible</code></li><li>category: <code>cloud</code></li><li>API key mode: <code>required</code></li><li>API test mode: <code>chat-only</code></li><li>base URL: international <code>https://api.z.ai/api/paas/v4</code></li><li>default model: <code>glm-5</code></li></ul><h3 id="_3-huawei-cloud-maas" tabindex="-1">3. Huawei Cloud MaaS <a class="header-anchor" href="#_3-huawei-cloud-maas" aria-label="Permalink to &quot;3. Huawei Cloud MaaS&quot;">​</a></h3><p><code>Huawei Cloud MaaS</code> should be added as a first-class preset for users running hosted DeepSeek/Qwen-class models behind Huawei Cloud.</p><p>Rationale:</p><ul><li>latest Cline includes it directly</li><li>it is a meaningful net-new entrypoint, not just a rename of an existing preset</li><li>its documented endpoint fits the current OpenAI-compatible runtime</li></ul><p>Expected shape:</p><ul><li>transport: <code>openai-compatible</code></li><li>category: <code>cloud</code></li><li>API key mode: <code>required</code></li><li>API test mode: <code>chat-only</code></li><li>base URL: <code>https://api.modelarts-maas.com/v1</code></li><li>default model: a stable Huawei-hosted model identifier such as <code>DeepSeek-V3</code></li></ul><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><h3 id="_1-provider-registry" tabindex="-1">1. Provider Registry <a class="header-anchor" href="#_1-provider-registry" aria-label="Permalink to &quot;1. Provider Registry&quot;">​</a></h3><p>Modify <code>src/llmProviders.ts</code> to:</p><ul><li>add <code>Qwen Code</code>, <code>Z AI</code>, and <code>Huawei Cloud MaaS</code></li><li>place them in a sensible order near related providers</li><li>provide accurate descriptions and setup hints</li><li>preserve existing provider ordering semantics used by the settings UI</li></ul><h3 id="_2-runtime-and-connection-testing" tabindex="-1">2. Runtime And Connection Testing <a class="header-anchor" href="#_2-runtime-and-connection-testing" aria-label="Permalink to &quot;2. Runtime And Connection Testing&quot;">​</a></h3><p>No new runtime branch should be added if the provider can route through <code>openai-compatible</code>.</p><p>The implementation should rely on current shared behavior:</p><ul><li><code>callLLM()</code> transport dispatch for OpenAI-compatible requests</li><li><code>testAPI()</code> provider-aware OpenAI-compatible probing</li><li>transient network fallback for both runtime calls and connection tests</li></ul><p>The new providers therefore need metadata, not custom runtime code paths, unless implementation review reveals a provider-specific incompatibility that is impossible to express through current metadata.</p><h3 id="_3-documentation" tabindex="-1">3. Documentation <a class="header-anchor" href="#_3-documentation" aria-label="Permalink to &quot;3. Documentation&quot;">​</a></h3><p>Update:</p><ul><li><code>README.md</code></li><li><code>README_zh.md</code></li><li><code>change.md</code></li></ul><p>Documentation should explain:</p><ul><li>that <code>Qwen Code</code> is a coding-focused preset</li><li>that <code>Z AI</code> complements rather than replaces <code>GLM</code></li><li>that <code>Huawei Cloud MaaS</code> is available as a hosted OpenAI-compatible option</li></ul><p>The provider lists, setup guidance, and preset-coverage sections should stay synchronized across both README files.</p><h3 id="_4-release" tabindex="-1">4. Release <a class="header-anchor" href="#_4-release" aria-label="Permalink to &quot;4. Release&quot;">​</a></h3><p>This work should ship as patch version <code>1.7.6</code> if no other unrelated feature lands first.</p><p>Release workflow requirements remain unchanged:</p><ul><li>bilingual GitHub release body with complete English and Chinese sections</li><li>release assets must include <code>main.js</code>, <code>manifest.json</code>, <code>styles.css</code>, and <code>README.md</code></li></ul><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>The new providers should inherit the existing shared retry and transient-failure fallback behavior.</p><p>This design does not add provider-specific error normalization. If any of the new providers later proves to need a unique response parser or nonstandard auth header, that should be handled in a separate design because it would expand protocol scope beyond this round.</p><p>The current rule stays in place:</p><ul><li>do not retry fatal client-status failures as transient network problems</li><li>do retry transient disconnects through the existing stable fallback path</li></ul><h2 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to &quot;Testing Strategy&quot;">​</a></h2><h3 id="provider-registry-tests" tabindex="-1">Provider Registry Tests <a class="header-anchor" href="#provider-registry-tests" aria-label="Permalink to &quot;Provider Registry Tests&quot;">​</a></h3><p>Extend <code>src/tests/llmProviders.test.ts</code> to:</p><ul><li>assert the presence of <code>Qwen Code</code>, <code>Z AI</code>, and <code>Huawei Cloud MaaS</code></li><li>assert their <code>transport</code> and <code>apiTestMode</code></li><li>confirm they are treated as OpenAI-compatible providers</li></ul><h3 id="runtime-routing-tests" tabindex="-1">Runtime Routing Tests <a class="header-anchor" href="#runtime-routing-tests" aria-label="Permalink to &quot;Runtime Routing Tests&quot;">​</a></h3><p>Extend <code>src/tests/llmUtilsProviderSupport.test.ts</code> to:</p><ul><li>assert <code>callLLM()</code> routes each new provider through the OpenAI-compatible runtime</li><li>assert the expected endpoint, auth header, and model value are used</li></ul><h3 id="connection-test-coverage" tabindex="-1">Connection Test Coverage <a class="header-anchor" href="#connection-test-coverage" aria-label="Permalink to &quot;Connection Test Coverage&quot;">​</a></h3><p>Extend <code>src/tests/llmUtilsProviderSupport.test.ts</code> to:</p><ul><li>assert <code>testAPI()</code> probes the expected <code>chat/completions</code> path for each new provider</li><li>assert transient disconnect fallback also works for these new presets during connection testing</li></ul><h3 id="full-verification" tabindex="-1">Full Verification <a class="header-anchor" href="#full-verification" aria-label="Permalink to &quot;Full Verification&quot;">​</a></h3><p>Before release:</p><ul><li>run targeted provider tests first during TDD</li><li>run <code>npm test -- --runInBand</code></li><li>run <code>npm run build</code></li><li>run <code>git diff --check</code></li><li>run the existing Obsidian CLI checks and report environment limits explicitly if they still fail in this machine context</li></ul><h2 id="review-notes" tabindex="-1">Review Notes <a class="header-anchor" href="#review-notes" aria-label="Permalink to &quot;Review Notes&quot;">​</a></h2><p>This design intentionally chooses only providers whose documented endpoints can be represented inside the current OpenAI-compatible transport. Providers requiring a dedicated SDK, signing flow, or new protocol layer are deferred.</p><p>A dedicated spec-review subagent was not used here because this session does not have explicit user authorization to delegate sub-agent work. This design was self-reviewed against the repository&#39;s current provider registry, test layout, and release rules, plus the latest public Cline provider catalog and provider docs consulted during design.</p>',70)])])}const m=i(r,[["render",n]]);export{u as __pageData,m as default};
